var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"사건번호 078853 <color=#ffd34c>알파트릭스 시큐리티 폭파 사건</color>\\n증거물 11호 - 통화 녹취록","JPN":"事件番号078853 <color=#ffd34c>アルファトリックスセキュリティ爆破事件</color>\\n証拠物件11号 - 通話録音記録","ENG":"Case number 078853, <color=#ffd34c>Alphatrix Security Explosion Incident</color>\\nExhibit 11 - Call logs","TWN":"案件編號 078853 <color=#ffd34c>阿爾法崔克斯證券爆炸事件</color>\\n證物11號 - 電話錄音紀錄"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"……그래. 자네 말대로 그 사람들이 여기 온 건 사실이야.","JPN":"……そうだ。君の言うとおり、あの者たちがここに来たのは事実だ。","ENG":"...Yes, it's like you said. They're here right now.","TWN":"……沒錯，就是你說的那樣，那些人在這裡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"하지만 대체 어떻게 알고 연락한 건가?","JPN":"だが、いったいどうやって知ったんだ？","ENG":"But how did you know to call me?","TWN":"但你是如何得知的？而且還找上我？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"회장님의 권한이면 그룹 전산망에 연결된 모든 장비의 데이터를 열람할 수 있습니다.","JPN":"会長の権限ならグループのネットワークに繋がれているすべての装備のデータを閲覧できます。","ENG":"With the President's authority, we have access to all data on any device that is connected to the company network.","TWN":"會長的權限可以瀏覽所有連上集團網路的裝備裡的數據，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"임직원용 어플리케이션이 설치된 이사님의 핸드폰도 말이죠.","JPN":"役員用のアプリがインストールされている常務のスマートフォンも例外ではありません。","ENG":"Including your phone that has the employee application installed on it.","TWN":"而理事您的手機裡也有安裝員工專屬的APP。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"그렇다면 시큐리티 시스템이 갑자기 작동했던 것도……","JPN":"では、セキュリティシステムが突然作動したのも……","ENG":"Then the security system suddenly going off is also...","TWN":"那保安系統會突然啟動也是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네. 둘 다 돌아가신 전 회장님의 유품이죠.","JPN":"はい。両方とも亡くなった元会長の遺産です。","ENG":"Yes. They are both mementos left behind by the late President.","TWN":"是的，這二個都是已故會長的遺物。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"그런가…… 평생을 바친 회사인데 까맣게 모르고 있었군.","JPN":"そうか……生涯を捧げた会社なのにまったく知らなかったな。","ENG":"I see... I've pledged my whole life to this company, and I never knew.","TWN":"是嗎……原來我對奉獻一生的公司一無所知。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"저희는 알파트릭스 시큐리티에 침입한 민병대를 경찰에 인계할 계획입니다.","JPN":"私たちはアルファトリックスセキュリティに進入した民兵隊を警察に引き渡すつもりです。","ENG":"We plan to turn in the Militia who broke into Alphatrix Security to the police.","TWN":"我們打算將入侵阿爾法崔克斯證券的民兵隊交給警方。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"좋아. 시간을 주면 내가 먼저 그들을 설득해 보겠네.","JPN":"わかった。時間をくれれば私がまず彼らを説得してみよう。","ENG":"OK. Give me some time so that I can persuade them.","TWN":"好吧，給我點時間，我會去說服他們。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"위험한 자들입니다. 이사님이 인질로 잡히실 수도 있어요.","JPN":"危険な者たちです。常務が人質になるかもしれません。","ENG":"They are dangerous folk. You could become their hostage.","TWN":"他們是危險分子，很可能會抓您來當人質。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"자신들이 막다른 골목에 몰렸다는 것만 알려 주면 돼.","JPN":"自分たちが袋小路に陥っているということさえ知らせられればいい。","ENG":"I just need to tell them that they're cornered and can't escape.","TWN":"我會跟他們說，他們已經無路可退，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"경찰과 총격전을 벌이다 죽느니 자수하는 게 더 낫다는 건 본인들이 가장 잘 알겠지.","JPN":"警察との銃撃戦の末に死ぬよりは自首した方がいいということは自分たちが一番よくわかっているだろう。","ENG":"They'll know it's better to turn themselves in than to start a shootout with the police.","TWN":"與其在和警方的槍戰中死亡，自首才是更好的選擇，這一點他們自己應該最清楚，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"이제까지 지은 죄가 있다지만, 그 편이 형량도 더 낮게…….","JPN":"今まで犯してきた罪があったとしても、その方が量刑も軽く……","ENG":"This way, they might get a lighter sentence for all their si─","TWN":"他們是有犯罪的事實，這樣或許可以減輕刑責……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"여보세요? 이사님, 제 말 들리시나요?","JPN":"もしもし？　常務、聞こえますか？","ENG":"Hello? Sir? Are you there?","TWN":"喂？理事，您有聽到我的聲音嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"무슨 일이죠? 대답해 보세요!","JPN":"どうされましたか？　答えてください！","ENG":"What's going on? Please answer me!","TWN":"發生什麼事？請您回答我！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"경찰이 당신들에 대해 수사 협조를 요청했습니다. 내버려 두면 위험한 인물이라면서 말이죠.","JPN":"警察があなたたちについての捜査協力を要請してきました。放っておくと危険な人物だそうです。","ENG":"The police have requested our cooperation to investigate you. They claim that you're too dangerous to be left alone.","TWN":"警方說你們是危險人物，因此請我們協助調查。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"하지만 저희 그룹 계열사에 침입한 건 예상 밖이었어요.","JPN":"ですが、私たちのグループの系列企業に進入したのは予想外でした。","ENG":"But we didn't imagine that you would infiltrate one of our companies.","TWN":"但我沒料到你們會入侵集團的分公司。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"피치 못할 사정이 있어서 말이지.","JPN":"やむを得ない事情があってな。","ENG":"We have our reasons.","TWN":"我們也是有苦衷的，"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"여기서 더 기물 파손을 저지를 생각은 없는데, 곱게 보내 줄 수 있겠나?","JPN":"ここでこれ以上器物破損をしたくはないんだが、静かに送り出してくれないか？","ENG":"We would hate to cause any more damage here. So would you kindly let us go?","TWN":"我們無意再造成你們的財務損失，可以放我們走嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그건 어렵겠네요. 손해배상 청구는 둘째 쳐도 시급히 확인해야 할 사안이 있어서요.","JPN":"それは無理ですね。損害賠償の請求はともかく、至急確認しなければならない事案がありますから。","ENG":"I'm afraid I can't do that. Besides compensation for the damage you caused, there is an urgent matter that needs to be attended to.","TWN":"恐怕有困難，先不說賠償金的部分，但有些事需要儘快釐清。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"우선 저 사람 옷에 묻은 피가 누구 것인지부터 들어야겠군요.","JPN":"まず、あの方の服についてる血はどなたのものかということから伺いましょう。","ENG":"First, I would like to know whose blood is on her clothes.","TWN":"就先說說，那個人身上沾到的血跡是誰的吧？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"으음? 누구예요, 저 아줌마?","JPN":"うーん？　誰です、あのおばさん？","ENG":"Hmm? Who's this woman?","TWN":"嗯？這位阿姨是誰？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"레비아……. 너 옷에 그 핏자국은 뭐야……?","JPN":"レヴィア……服のその血の跡はどうしたんだ……？","ENG":"Levia... Why are you covered in blood...?","TWN":"莉維亞……你身上的血跡是怎麼回事……？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"아, 이거?","JPN":"あ、これ？","ENG":"Oh, this?","TWN":"喔～你說這個喔？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그 의뢰인이었다는 아저씨 거. 역시 내통하고 있었더라고.","JPN":"あの依頼人だったっていうおじさんの血。やっぱり内通してましたよ。","ENG":"That so-called client of ours. He was colluding with someone behind our backs.","TWN":"就那個委託人大叔的，他果然是內鬼！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"내통이라고? 그게 말이나 돼?","JPN":"内通？　まさか。","ENG":"Colluding? That makes no sense.","TWN":"什麼內鬼？你在胡說什麼？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그런 반응이 있을까 봐 착실하게 녹음까지 해 왔다구요.","JPN":"そういう反応が返ってくるだろうと思って、念のため録音までしてきたんですから。","ENG":"I thought you'd say that, so I recorded him talking on his phone.","TWN":"我就知道你會是這種反應，幸好我有錄音！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"<color=#ffd34c>좋아. 시간을…… 내가 먼저 ………설득해 보겠네.</color>","JPN":"<color=#ffd34c>わかった。時間を……私がまず……説得してみよう。</color>","ENG":"<color=#ffd34c>Very well. Give... some time... persuade them.</color>","TWN":"<color=#ffd34c>好吧，時間……我會去………說服他們。</color>"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"<color=#ffd34c>자신들이 막다른 골…… 몰……는 것만 알려 주면 돼.</color>","JPN":"<color=#ffd34c>自分たちが袋小……陥っ……いうことさえ知らせられればいい。</color>","ENG":"<color=#ffd34c>I just need to... corner... and... escape.</color>","TWN":"<color=#ffd34c>我會跟他們說，他……們已經……可退，</color>"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"<color=#ffd34c>경찰과 총……… 벌이다 죽느니 자……는 게 더 ……는 건 본인들이 가장 잘 알겠지.</color>","JPN":"<color=#ffd34c>警察との銃……末に死ぬよりは自……方がい……ことは自分たちが一番よくわかっているだろう。</color>","ENG":"<color=#ffd34c>...Better... than to start.... shootout with the police.</color>","TWN":"<color=#ffd34c>……在和警方的槍………中死亡……不如…這一點他們自己應該最清楚。</color>"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"빌어먹을……. 일이 단단히 꼬였군.","JPN":"くそ……こじれたな。","ENG":"Dammit... We are royally screwed.","TWN":"該死……看樣子是沒什麼好談的！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이유리, 레비아. 총알은 얼마나 남았지?","JPN":"カスカベ、レヴィア。銃弾はどれくらい残ってる？","ENG":"Yuri, Levia. How much ammo you got left?","TWN":"李悠麗、莉維亞，還剩多少子彈？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……아직 넉넉해. 카운터 상대로는 모자란 것 같지만.","JPN":"……まだ十分。カウンター相手では足りないかもしれないけど。","ENG":"...Enough. But not enough to go up against a Counter.","TWN":"……還剩很多，但可能不夠拿來對付制裁者。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"언니, 그건 무기고를 짊어지고 다녀도 안 달라질 걸요.","JPN":"ユリさん、それは武器庫を丸ごと持ち歩いてても同じですよ。","ENG":"Yuri, it wouldn't make a difference even if we raided an armory.","TWN":"姊姊，就算我們有一整個武器庫好像也沒勝算欸？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"알파트릭스 소속을 건드리면 뒤가 없어. 빈틈을 만들고 이탈한다.","JPN":"アルファトリックス所属の者に手を出せば未来がない。隙を作って離脱する。","ENG":"There's no turning back if we attack Alphatrix. We make our opening and get the hell out of here.","TWN":"動阿爾法崔克斯的人就是死路一條，我們要製造機會逃跑。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"묵비권을 행사하시겠다면 어쩔 수 없죠.","JPN":"黙秘権を行使するというのなら仕方ありません。","ENG":"If you plead the fifth, then I guess I have no other choice.","TWN":"看來你們打算行使緘默權嗎？那就沒辦法囉。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"카운터를 살해할 만큼의 역량이 있다고 들었습니다만, 저는 쉽게 당해드리지 않을 겁니다.","JPN":"カウンターを殺すほどの力量があると聞きましたが、私はそう簡単にやられません。","ENG":"I heard you were capable of even killing a Counter. However, I won't be that easy to kill.","TWN":"我聽說你們的實力足以殺害制裁者，但我可沒那麼好對付。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 혼자서 나타난 녀석들 모두 그렇게 말하더군.","JPN":"ああ。一人で現れるやつはみんなそう言っていたな。","ENG":"Sure. That's what they all say when they show up alone.","TWN":"是嗎？那些單槍匹馬來的人都喜歡虛張聲勢。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"혼자라니요. 엄호는 대 침식전에서 기본 소양입니다.","JPN":"一人だなんて。援護は対侵食戦では基本です。","ENG":"Alone? Having cover is the basics of Anti-Corruption warfare.","TWN":"誰說我單槍匹馬來的？掩護是對付侵蝕體時的基本素養。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"회장님네 의뢰라고 해서 왔더니 사람 상대하는 일인 줄은 몰랐는데.","JPN":"会長の依頼だと聞いて来てみたが、まさか人間相手の仕事だとはな。","ENG":"I heard it was a request of the President, but I didn't know I would be fighting against people.","TWN":"說是會長的委託我才來的，結果是要對付人喔？"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"폼 잡지 말고 진지하게 굴어. 오르카도 없는 마당에.","JPN":"格好つけてないで真面目にやりなさいよ。オルカもいないんだから。","ENG":"Stop acting all tough and be serious. We don't even have Orca right now.","TWN":"少在那邊說些有的沒的，給我認真點，而且奧爾卡現在又不在。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"허, 참. 우리 사장님 머릿속은 도통 모르겠어. 갑자기 장기 휴가 내라고 그렇게 야단이라니.","JPN":"はっ、まったく。社長の頭ん中はどうなってるんだか。いきなり長期休暇願い出せってうるさかったのにな。","ENG":"Geez, I'll never understand what goes on inside Boss' head. Why did he tell Orca to take that long vacation?","TWN":"真是的，完全搞不懂老闆的腦袋在想什麼，突然兇我，叫我放長假欸！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"민우 대장, 무전기에 노이즈가 잡히는데요. 다른 녀석들도 왔나 봐요.","JPN":"マツダ隊長、無線にノイズが入ってますよ。他のやつらも来たみたいです。","ENG":"Captain, I'm hearing some noise through our comms. I'm guessing they got company.","TWN":"民宇隊長，無線電有雜音，看來還有其他人。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 멍청하게 정면으로 나왔던 용병들과는 질이 다른 녀석들 같다. 조심해.","JPN":"ああ。正面から出てきたバカな傭兵たちとは質が違うようだ。気をつけろ。","ENG":"Yeah. At least they're better than those idiot mercs who tried to face us head on. Stay sharp.","TWN":"嗯嗯，他們沒有冒然衝出來，應該和那些頭腦簡單的傭兵不太一樣，大家小心。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"사옥에서 폭력을 저지른 이상 손님 대접을 해 드릴 수는 없죠.","JPN":"社内で暴力事件を起こした以上、お客様としておもてなしすることはできません。","ENG":"As you committed violence in the company, I can no longer treat you as a guest.","TWN":"你們在公司施暴的話，那我也無法拿出我的待客之道。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"단호히 제압해 드리겠습니다.","JPN":"断固制圧させていただきます。","ENG":"We have no choice but to apprehend you.","TWN":"我會不客氣地壓制你們。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};